import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [parkingData, setParkingData] = useState({
    status: {},
    stats: { total: 0, occupied: 0, available: 0, occupancy_rate: 0 }
  });
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [lastUpdate, setLastUpdate] = useState(new Date());
  const [videoFile, setVideoFile] = useState(null);
  const [cameraStream, setCameraStream] = useState(null);
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [annotations, setAnnotations] = useState([]);
  const [currentFrame, setCurrentFrame] = useState(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [startPos, setStartPos] = useState({x: 0, y: 0});

  const startAnnotation = () => {
    const video = document.getElementById('camera-video');
    if (video && video.videoWidth > 0) {
      const canvas = document.createElement('canvas');
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(video, 0, 0);
      const dataURL = canvas.toDataURL('image/jpeg');
      setCurrentFrame(dataURL);
      setIsAnnotating(true);
      setAnnotations([]);
    } else {
      alert('No video available for annotation');
    }
  };

  const handleCanvasMouseDown = (e) => {
    const rect = e.target.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setStartPos({x, y});
    setIsDrawing(true);
  };

  const handleCanvasMouseUp = (e) => {
    if (!isDrawing) return;
    const rect = e.target.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const width = x - startPos.x;
    const height = y - startPos.y;
    if (width > 10 && height > 10) {
      const newAnnotation = {
        x: startPos.x,
        y: startPos.y,
        width,
        height
      };
      setAnnotations([...annotations, newAnnotation]);
    }
    setIsDrawing(false);
  };

  const saveAnnotations = async () => {
    const parkingAreas = annotations.map((ann, idx) => ({
      id: `slot${idx + 1}`,
      bbox: [ann.x, ann.y, ann.x + ann.width, ann.y + ann.height]
    }));
    try {
      const response = await fetch('http://localhost:8000/update-parking-slots', {
        method: 'POST',
        body: JSON.stringify({ parking_slots: parkingAreas }),
        headers: { 'Content-Type': 'application/json' },
      });
      const result = await response.json();
      alert(result.message);
      setIsAnnotating(false);
    } catch (error) {
      console.error('Save failed:', error);
    }
  };

  if (isAnnotating) {
    return (
      <div className="annotation">
        <h1>Annotate Parking Slots</h1>
        <div className="annotation-canvas">
          <canvas
            width={640}
            height={480}
            style={{ backgroundImage: `url(${currentFrame})`, backgroundSize: 'cover' }}
            onMouseDown={handleCanvasMouseDown}
            onMouseUp={handleCanvasMouseUp}
          />
          {annotations.map((ann, idx) => (
            <div
              key={idx}
              className="annotation-box"
              style={{
                position: 'absolute',
                left: `${ann.x}px`,
                top: `${ann.y}px`,
                width: `${ann.width}px`,
                height: `${ann.height}px`,
                border: '2px solid red',
                pointerEvents: 'none'
              }}
            />
          ))}
        </div>
        <div className="annotation-controls">
          <button onClick={saveAnnotations}>Save Annotations</button>
          <button onClick={() => setIsAnnotating(false)}>Cancel</button>
        </div>
      </div>
    );
  }

  useEffect(() => {
    const ws = new WebSocket('ws://localhost:8000/ws/parking-updates');

    ws.onopen = () => setIsLoading(false);
    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        setParkingData(data);
        setLastUpdate(new Date());
        setError(null);
      } catch (e) {
        setError('Failed to parse data');
      }
    };
    ws.onerror = () => setError('Connection error');
    ws.onclose = () => setError('Connection closed');

    return () => ws.close();
  }, []);

  const handleFileChange = (e) => {
    setVideoFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!videoFile) return;
    const formData = new FormData();
    formData.append('file', videoFile);
    try {
      const response = await fetch('http://localhost:8000/upload-video', {
        method: 'POST',
        body: formData,
      });
      const result = await response.json();
      alert(result.message);
    } catch (error) {
      console.error('Upload failed:', error);
    }
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      setCameraStream(stream);
      const video = document.getElementById('camera-video');
      video.srcObject = stream;
    } catch (error) {
      console.error('Camera access denied:', error);
    }
  };

  const stopCamera = () => {
    if (cameraStream) {
      cameraStream.getTracks().forEach(track => track.stop());
      setCameraStream(null);
    }
  };

  const detectFrame = async () => {
    const video = document.getElementById('camera-video');
    if (!video.videoWidth || !video.videoHeight) {
      alert('Video not ready');
      return;
    }
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0);
    const dataURL = canvas.toDataURL('image/jpeg');
    const base64 = dataURL.split(',')[1];
    try {
      const response = await fetch('http://localhost:8000/detect-frame', {
        method: 'POST',
        body: JSON.stringify({ image: base64 }),
        headers: { 'Content-Type': 'application/json' },
      });
      const result = await response.json();
      setDetectedImage('data:image/jpeg;base64,' + result.image);
    } catch (error) {
      console.error('Detection failed:', error);
    }
  };

  if (isLoading) return <div className="loading">Loading parking data...</div>;
  if (error) return <div className="error">Error: {error}</div>;

  const { status, stats } = parkingData;
  const slotLabels = Object.keys(status);
  const availableSlots = slotLabels.filter(slot => status[slot] === 'available');
  const highOccupancy = stats.occupancy_rate > 80;

  return (
    <div className="app">
      <header className="header">
        <h1>🚗 Smart Parking</h1>
        <div className="update-time">Updated: {lastUpdate.toLocaleTimeString()}</div>
        {highOccupancy && <div className="alert">⚠️ Parking is almost full!</div>}
      </header>

      <main className="main">
        <section className="upload-section">
          <h2>Upload Video or Use Camera</h2>
          <div className="upload-controls">
            <input type="file" accept="video/*" onChange={handleFileChange} />
            <button onClick={handleUpload}>Upload Video</button>
          </div>
          <div className="camera-controls">
            <button onClick={startCamera}>Start Camera</button>
            <button onClick={stopCamera}>Stop Camera</button>
            <button onClick={detectFrame}>Detect Vehicles</button>
            <button onClick={startAnnotation}>Annotate Parking Slots</button>
            <video id="camera-video" autoPlay style={{ width: '300px', border: '1px solid #ccc' }}></video>
            {detectedImage && <img src={detectedImage} alt="Detected" style={{ width: '300px', border: '1px solid #ccc' }} />}
          </div>
        </section>

        <section className="stats-section">
          <div className="stats-grid">
            <div className="stat-card total">
              <div className="stat-number">{stats.total}</div>
              <div className="stat-label">Total Spaces</div>
            </div>
            <div className="stat-card available">
              <div className="stat-number">{stats.available}</div>
              <div className="stat-label">Available</div>
            </div>
            <div className="stat-card occupied">
              <div className="stat-number">{stats.occupied}</div>
              <div className="stat-label">Occupied</div>
            </div>
            <div className={`stat-card rate ${highOccupancy ? 'high' : ''}`}>
              <div className="stat-number">{stats.occupancy_rate}%</div>
              <div className="stat-label">Occupancy</div>
            </div>
          </div>
        </section>

        <section className="parking-section">
          <h2>Parking Overview</h2>
          <div className="available-info">
            <h3>Available Spots ({availableSlots.length})</h3>
            <div className="available-list">
              {availableSlots.length > 0 ? availableSlots.map(slot => (
                <span key={slot} className="available-slot">{slot}</span>
              )) : <span className="no-slots">No available slots</span>}
            </div>
          </div>
          <div className="parking-grid">
            {slotLabels.map(slot => (
              <div
                key={slot}
                className={`parking-spot ${status[slot]}`}
              >
                <div className="spot-number">{slot}</div>
                <div className="spot-status">{status[slot]}</div>
              </div>
            ))}
          </div>
        </section>
      </main>

      <footer className="footer">
        <p>Real-time parking management system</p>
      </footer>
    </div>
  );
}

export default App;
